import{_ as r,o as i,c as a,ag as o}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"Core 模块架构","description":"","frontmatter":{},"headers":[],"relativePath":"core.md","filePath":"core.md","lastUpdated":1774533461000}'),l={name:"core.md"};function d(c,e,t,n,s,p){return i(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="core-模块架构" tabindex="-1">Core 模块架构 <a class="header-anchor" href="#core-模块架构" aria-label="Permalink to &quot;Core 模块架构&quot;">​</a></h1><p>Core 层负责的是“driver 发出的流怎么进入系统、怎么路由、怎么录制、怎么被其他模块消费”。</p><p>如果需要概括 Core 层的定位，可以理解为：</p><ul><li>UI 和应用层依赖 Core 暴露出来的稳定流模型，而不是直接依赖设备协议</li></ul><h2 id="core-负责什么" tabindex="-1">Core 负责什么 <a class="header-anchor" href="#core-负责什么" aria-label="Permalink to &quot;Core 负责什么&quot;">​</a></h2><p>当前 Core 主要负责这几件事：</p><ol><li>托管 driver worker thread</li><li>调 driver 的生命周期方法</li><li>接住 driver 发出的 <code>FrameEnvelope</code></li><li>把 descriptor 注册到 <code>StreamBus</code></li><li>把实时流交给录制和其他消费者</li></ol><h2 id="建议优先了解的几个对象" tabindex="-1">建议优先了解的几个对象 <a class="header-anchor" href="#建议优先了解的几个对象" aria-label="Permalink to &quot;建议优先了解的几个对象&quot;">​</a></h2><h3 id="driverportal" tabindex="-1"><code>DriverPortal</code> <a class="header-anchor" href="#driverportal" aria-label="Permalink to &quot;`DriverPortal`&quot;">​</a></h3><p><code>DriverPortal</code> 是系统其他部分接触 driver 的入口。</p><p>它负责：</p><ul><li>转发 <code>search / connect / disconnect / start / stop</code></li><li>维护 driver 的连接状态和 streaming 状态</li><li>接住来自 driver 的 frame 和 connection-lost 事件</li></ul><h3 id="driverruntime" tabindex="-1"><code>DriverRuntime</code> <a class="header-anchor" href="#driverruntime" aria-label="Permalink to &quot;`DriverRuntime`&quot;">​</a></h3><p><code>DriverRuntime</code> 负责把 driver 放到独立 <code>QThread</code> 上运行，并通过 invoker 把方法调用投递到这条线程。</p><p>从 driver 侧看，这意味着：</p><ul><li>生命周期方法仍然是同步方法</li><li>但不会直接堵住 UI 线程</li></ul><h3 id="streambus" tabindex="-1"><code>StreamBus</code> <a class="header-anchor" href="#streambus" aria-label="Permalink to &quot;`StreamBus`&quot;">​</a></h3><p><code>StreamBus</code> 是系统内部的统一流入口。</p><p>它的角色是：</p><ul><li>注册 <code>StreamDescriptor</code></li><li>接收实时 <code>FrameEnvelope</code></li><li>给录制和 UI 提供统一的订阅源</li></ul><h3 id="acquisitionbackend" tabindex="-1"><code>AcquisitionBackend</code> <a class="header-anchor" href="#acquisitionbackend" aria-label="Permalink to &quot;`AcquisitionBackend`&quot;">​</a></h3><p><code>AcquisitionBackend</code> 负责录制任务。</p><p>它不需要知道设备怎么连接，只关心总线里已经存在的流以及如何把这些流写出去。</p><h3 id="modlinkengine" tabindex="-1"><code>ModLinkEngine</code> <a class="header-anchor" href="#modlinkengine" aria-label="Permalink to &quot;`ModLinkEngine`&quot;">​</a></h3><p><code>ModLinkEngine</code> 是整个 Core 的组合根。</p><p>它负责：</p><ul><li>创建 <code>StreamBus</code></li><li>创建录制后端</li><li>安装 driver portal</li><li>把这些共享服务挂在一起</li></ul><h2 id="一个-frame-的流转路径" tabindex="-1">一个 frame 的流转路径 <a class="header-anchor" href="#一个-frame-的流转路径" aria-label="Permalink to &quot;一个 frame 的流转路径&quot;">​</a></h2><p>典型路径如下：</p><ol><li>driver 发出 <code>sig_frame(FrameEnvelope)</code></li><li><code>DriverRuntime</code> 接到这个 signal</li><li><code>DriverPortal</code> 把它继续往上转</li><li><code>StreamBus</code> 接收并分发</li><li>录制后端和 UI 消费者分别订阅</li></ol><p>对展示层来说，最重要的是最后两步，而不是设备底层怎么来的。</p><h2 id="为什么-descriptor-要尽量稳定" tabindex="-1">为什么 descriptor 要尽量稳定 <a class="header-anchor" href="#为什么-descriptor-要尽量稳定" aria-label="Permalink to &quot;为什么 descriptor 要尽量稳定&quot;">​</a></h2><p>当前 engine 在安装 driver 时就会先读取 <code>descriptors()</code> 并把它们注册到总线里。</p><p>这意味着：</p><ul><li>descriptor 最好不要依赖“先连上设备之后才能知道”的动态状态</li><li><code>stream_id</code>、<code>payload_type</code>、<code>chunk_size</code> 这些字段最好在 driver 生命周期内保持稳定</li></ul><p>这不是因为系统不能做动态 descriptor，而是因为目前整条链路还没有把“连接后重新注册 descriptor”作为主流程。</p><h2 id="对-driver-开发更直接相关的部分" tabindex="-1">对 driver 开发更直接相关的部分 <a class="header-anchor" href="#对-driver-开发更直接相关的部分" aria-label="Permalink to &quot;对 driver 开发更直接相关的部分&quot;">​</a></h2><p>如果关注点是编写 driver，建议优先了解的是：</p><ul><li><code>sig_frame</code> 会进入 <code>StreamBus</code></li><li><code>StreamDescriptor</code> 会先被注册</li><li>生命周期方法在 worker thread 上同步执行</li></ul><p>理解这些边界之后，通常不需要再了解过多的 Core 内部实现细节。</p><h2 id="对展示开发更直接相关的部分" tabindex="-1">对展示开发更直接相关的部分 <a class="header-anchor" href="#对展示开发更直接相关的部分" aria-label="Permalink to &quot;对展示开发更直接相关的部分&quot;">​</a></h2><p>如果关注点是页面、图表或面板，更适合优先依赖的是这些约定：</p><ul><li><code>stream_id</code></li><li><code>payload_type</code></li><li><code>data.shape</code></li><li><code>channel_names</code></li><li><code>unit</code></li></ul><p>也就是说，UI 更适合消费“已经稳定化的流模型”，而不是消费设备自己的底层概念。</p><h2 id="推荐继续阅读的页面" tabindex="-1">推荐继续阅读的页面 <a class="header-anchor" href="#推荐继续阅读的页面" aria-label="Permalink to &quot;推荐继续阅读的页面&quot;">​</a></h2><ul><li>想接设备：看 <a href="/sdk">SDK</a></li><li>想做页面展示：看 <a href="/ui">UI</a></li><li>想知道应用入口怎么组装：看 <a href="/app">App</a></li><li>想直接跳源码 API：看 <a href="/api">API</a></li></ul>',46)])])}const m=r(l,[["render",d]]);export{u as __pageData,m as default};
